class Solution {
    public String minimizeStringValue(String s) {
        StringBuilder sb = new StringBuilder();
        for (char c : s.toCharArray()) {
            if (c == '?') {
                sb.append('a');
            } else {
                sb.append(c);
            }
        }
        return sb.toString();
    }
}
